The fix is to update the CFG for blocks that become unreachable due to non-returning calls *before* we start collecting and deleting dead blocks based on reachability. The logic to replace terminators with `unreachable` should be moved before the loop that populates `BBsWithNoPreds`.

I will move the block of code that replaces terminators of unreachable blocks to be before the collection of dead blocks.

```bash
sed -i -e '223,241d' -e '218r /dev/stdin' llvm/lib/Transforms/IPO/SCCP.cpp <<'EOF'
  // If we found a non-returning call, we must insert an unreachable
  // instruction after it.
  if (Changed) {
    SmallVector<BasicBlock *, 16> BBs;
    for (Function &F : M)
      if (!F.isDeclaration())
        for (BasicBlock &BB : F)
          BBs.push_back(&BB);

    for (BasicBlock *BB : BBs) {
      if (isBlockExecutable(BB))
        continue;
      // This block is not executable. If it does not contain a 'ret' or
      // 'unreachable' instruction, it must be because it is unreachable.
      // Change the terminator to an unreachable instruction.
      if (isa<ReturnInst>(BB->getTerminator()) ||
          isa<UnreachableInst>(BB->getTerminator()))
        continue;

      // Don't change the terminator of a landing pad.
      if (BB->isLandingPad())
        continue;

      for (BasicBlock *Succ : successors(BB))
        Succ->removePredecessor(BB);
      BB->getTerminator()->eraseFromParent();
      new UnreachableInst(BB->getContext(), BB);
      DTU.applyUpdates({{DominatorTree::Delete, BB, BB}});
    }
  }
EOF
```

